#include<bits/stdc++.h>
using namespace std;
int nextt[1000005],m;
    string b;
void nexts(){
    nextt[0]=0;
    nextt[1]=0;
    for(int i=0,j=2;j<=m;j++){
        while(b[i]!=b[j-1]) {
            if(i==0) {
                i=-1;
                break;
            }
            i=nextt[i];
        }
        i++;
        nextt[j]=i;
    }
}

int main(){
    cin>>m;
    cin>>b;
    nexts();
    cout<<m-nextt[m];
    return 0;
}
